const fs = require('fs');
fs.mkdirSync('src/lib', { recursive: true });
fs.writeFileSync('src/app/page.tsx', "'use client';\nimport React from 'react';\nimport { useState, useEffect, useCallback, useRef } from 'react';\nimport PollCard from '@/components/PollCard';\nimport CreatePollModal from '@/components/CreatePollModal';\nimport CityMap from '@/components/CityMap';\nimport { subscribeToPolls, getUserVotes, castVote, createPoll, seedPolls, ensureAuth, signInWithGoogle } from '@/lib/polls';\nimport { auth, db } from '@/lib/firebase';\nimport WhatsAppModal from '@/components/WhatsAppModal';\nimport AuthModal from '@/components/AuthModal';\nimport { doc, getDoc, setDoc } from 'firebase/firestore';\nimport { onAuthStateChanged, User, signOut } from 'firebase/auth';\n\nfunction fmt(n: number) {\n  if (n >= 1000000) return (n / 1000000).toFixed(1) + 'M';\n  if (n >= 1000) return (n / 1000).toFixed(1) + 'k';\n  return String(n);\n}\n\nfunction HomeCore() {\n  const highlightSlug = typeof window !== 'undefined' ? sessionStorage.getItem('highlightSlug') || undefined : undefined;\n  const [polls, setPolls] = useState<any[]>([]);\n  const [votes, setVotes] = useState<Record<string, string>>({});\n  const [user, setUser] = useState<User | null>(null);\n  const [tab, setTab] = useState<'feed' | 'trending' | 'perfil'>('feed');\n  const [showCreate, setShowCreate] = useState(false);\n  const [showCity, setShowCity] = useState<string | null>(null);\n  const [streak, setStreak] = useState(0);\n  const [notif, setNotif] = useState<string | null>(null);\n  const [loading, setLoading] = useState(true);\n  const [city, setCity] = useState<string | null>(null);\n  const [search, setSearch] = useState('');\n  const [activeTag, setActiveTag] = useState<string | null>(null);\n  const [showWhatsApp, setShowWhatsApp] = useState(false);\n  const [showAuth, setShowAuth] = useState(false);\n  const [votaCoins, setVotaCoins] = useState(0);\n  const [highlightedId, setHighlightedId] = useState<string | null>(null);\n  const pollRefs = useRef<Record<string, HTMLDivElement | null>>({});\n  const hasVotedRef = useRef(false);\n  const [isSubscribed, setIsSubscribed] = useState(false);\n\n  // Auth\n  useEffect(() => {\n    const unsub = onAuthStateChanged(auth, async (u) => {\n      if (!u) {\n        const user = await ensureAuth();\n        setUser(user);\n      } else {\n        setUser(u);\n        // Load votaCoins and save profile if not anonymous\n        if (!u.isAnonymous && u.email) {\n          getDoc(doc(db, 'members', u.uid)).then(snap => {\n            if (snap.exists()) {\n              const data = snap.data();\n              setVotaCoins(data?.votaCoins || 0);\n              if (data?.phone) setIsSubscribed(true); // already has WhatsApp\n            }\n            setDoc(doc(db, 'members', u.uid), {\n              email: u.email,\n              displayName: u.displayName || null,\n              provider: u.providerData[0]?.providerId || 'password',\n              joinedAt: u.metadata.creationTime || null,\n              lastLogin: new Date().toISOString(),\n              uid: u.uid,\n            }, { merge: true }).catch(e => console.error('members write error:', e));\n          }).catch(() => null);\n        }\n      }\n    });\n    return unsub;\n  }, []);\n\n  // Geolocation\n  useEffect(() => {\n    fetch('https://ipapi.co/json/')\n      .then(r => r.json())\n      .then(d => setCity(d.city || null))\n      .catch(() => null);\n  }, []);\n\n  // Polls \u2014 wait for auth before subscribing\n  useEffect(() => {\n    if (!user) return;\n    seedPolls().catch(() => null);\n    const unsub = subscribeToPolls((p) => {\n      const sorted = [...p].sort((a, b) => {\n        if (a.pinned && !b.pinned) return -1;\n        if (!a.pinned && b.pinned) return 1;\n        return 0;\n      });\n      setPolls(sorted);\n      setLoading(false);\n    });\n    return unsub;\n  }, [user]);\n\n  // Scroll to highlighted poll\n  useEffect(() => {\n    if (!highlightSlug || polls.length === 0) return;\n    const poll = polls.find(p => p.slug === highlightSlug);\n    if (!poll) return;\n    setHighlightedId(poll.id);\n    setTimeout(() => {\n      const el = pollRefs.current[poll.id];\n      if (el) {\n        el.scrollIntoView({ behavior: 'smooth', block: 'center' });\n        setTimeout(() => setHighlightedId(null), 3000);\n      }\n    }, 500);\n  }, [highlightSlug, polls]);\n\n  // User votes + check subscription\n  useEffect(() => {\n    if (!user) return;\n    getUserVotes(user.uid).then(v => {\n      setVotes(v);\n      if (Object.keys(v).length > 0) hasVotedRef.current = true;\n    });\n    getDoc(doc(db, 'subscribers', user.uid)).then(snap => {\n      if (snap.exists()) setIsSubscribed(true);\n    }).catch(() => null);\n  }, [user]);\n\n  const showNotif = (msg: string) => {\n    setNotif(msg);\n    setTimeout(() => setNotif(null), 2500);\n  };\n\n  const handleVote = useCallback(async (id: string, choice: string) => {\n    if (!user || votes[id]) return;\n    setVotes(v => ({ ...v, [id]: choice }));\n    const ns = streak + 1;\n    setStreak(ns);\n    if (ns === 3) showNotif('\ud83d\udd25 3 seguidas! Voc\u00ea t\u00e1 no flow!');\n    else if (ns === 5) showNotif('\u26a1 5 votos! Vicia f\u00e1cil hein?');\n    else if (ns === 10) showNotif('\ud83d\udc51 10 votos! Rei das enquetes!');\n    await castVote(id, choice, user.uid, city || undefined, user.isAnonymous);\n    if (!user.isAnonymous) setVotaCoins(c => c + 1);\n    // Show WhatsApp modal after first vote if not subscribed\n    if (!hasVotedRef.current) {\n      hasVotedRef.current = true;\n      const sub = await getDoc(doc(db, 'subscribers', user.uid));\n      if (!sub.exists()) setTimeout(() => setShowWhatsApp(true), 1500);\n    }\n  }, [user, votes, streak, city]);\n\n  const handleCreate = async (data: any) => {\n    if (!user) return;\n    await createPoll({ ...data, userId: user.uid });\n    showNotif('\ud83c\udf89 Enquete publicada!');\n  };\n\n  const handleGoogleLogin = async () => {\n    try {\n      await signInWithGoogle();\n      showNotif('\u2705 Login feito com sucesso!');\n    } catch (e) {\n      showNotif('\u274c Erro ao fazer login');\n    }\n  };\n\n  const hotPoll = polls.find(p => p.hotOfDay);\n  const trending = [\n    ...(hotPoll ? [hotPoll] : []),\n    ...[...polls]\n      .filter(p => !p.hotOfDay)\n      .sort((a, b) => (b.totalVotes || 0) - (a.totalVotes || 0))\n  ];\n  const allTags = ['todos', ...Array.from(new Set(polls.map(p => p.tag).filter(Boolean)))].slice(0, 12);\n  const filteredPolls = polls.filter(p => {\n    const matchesTag = !activeTag || activeTag === 'todos' || p.tag === activeTag;\n    const matchesSearch = !search || p.question?.toLowerCase().includes(search.toLowerCase()) ||\n      p.optionA?.label?.toLowerCase().includes(search.toLowerCase()) ||\n      p.optionB?.label?.toLowerCase().includes(search.toLowerCase());\n    return matchesTag && matchesSearch;\n  });\n  const votedCount = Object.keys(votes).length;\n  const isAnon = user?.isAnonymous;\n\n  return (\n    <div className=\"min-h-screen\" style={{ background: '#07070E' }}>\n      {/* Notification */}\n      {notif && (\n        <div className=\"fixed top-4 left-1/2 -translate-x-1/2 z-50 px-5 py-3 rounded-2xl text-white font-bold text-sm shadow-2xl animate-fade-up\" style={{ background: '#6C63FF', minWidth: 200, textAlign: 'center' }}>\n          {notif}\n        </div>\n      )}\n\n      {/* Desktop layout */}\n      <div className=\"max-w-6xl mx-auto flex min-h-screen\" style={{ width: '100%' }}>\n\n        {/* Sidebar */}\n        <aside className=\"hidden md:flex flex-col w-64 p-6 sticky top-0 h-screen border-r\" style={{ borderColor: 'rgba(255,255,255,0.06)' }}>\n          <div className=\"mb-10\">\n            <a href=\"/\" className=\"text-4xl text-white\" style={{ fontFamily: 'var(--font-display)', letterSpacing: '0.05em', textDecoration: 'none' }}>VOTAAI</a>\n            <p className=\"text-xs mt-1\" style={{ color: 'rgba(255,255,255,0.3)' }}>Qual \u00e9 a sua?</p>\n          </div>\n\n          <nav className=\"space-y-1 flex-1\">\n            {[\n              { id: 'feed', icon: '\ud83c\udfe0', label: 'Feed' },\n              { id: 'trending', icon: '\ud83d\udcc8', label: 'Trending' },\n              { id: 'perfil', icon: '\ud83d\udc64', label: 'Perfil' },\n            ].map(item => (\n              <button\n                key={item.id}\n                onClick={() => setTab(item.id as any)}\n                className=\"w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-bold transition-all text-left\"\n                style={{\n                  background: tab === item.id ? 'rgba(108,99,255,0.15)' : 'transparent',\n                  color: tab === item.id ? '#6C63FF' : 'rgba(255,255,255,0.5)',\n                }}\n              >\n                <span className=\"text-lg\">{item.icon}</span> {item.label}\n              </button>\n            ))}\n          </nav>\n\n          <div className=\"space-y-3\">\n            {streak >= 3 && (\n              <div className=\"px-4 py-3 rounded-xl text-sm font-bold\" style={{ background: '#FF6B3520', color: '#FF6B35' }}>\n                \ud83d\udd25 Streak de {streak}!\n              </div>\n            )}\n            <button\n              onClick={() => setShowCreate(true)}\n              className=\"w-full py-3 rounded-xl font-black text-sm text-white transition-all hover:opacity-90 animate-pulse-glow\"\n              style={{ background: '#6C63FF', fontFamily: 'var(--font-display)', letterSpacing: '0.1em', fontSize: '1rem' }}\n            >\n              + CRIAR\n            </button>\n            {isAnon ? (\n              <button onClick={() => setShowAuth(true)} className=\"w-full py-3 rounded-xl text-sm font-bold border transition-all hover:bg-white/5\" style={{ borderColor: '#6C63FF66', color: '#6C63FF' }}>\n                \ud83d\udc64 Entrar / Cadastrar\n              </button>\n            ) : (\n              <div className=\"px-3 py-2 rounded-xl text-xs\" style={{ background: 'rgba(255,255,255,0.04)', color: 'rgba(255,255,255,0.3)' }}>\n                \ud83d\udc64 {user?.displayName || user?.email || 'An\u00f4nimo'}\n              </div>\n            )}\n          </div>\n        </aside>\n\n        {/* Fixed mobile header */}\n        <header className=\"fixed top-0 left-0 right-0 z-40 flex items-center justify-between px-4 py-3 md:hidden\" style={{ background: 'rgba(7,7,14,0.92)', backdropFilter: 'blur(12px)', borderBottom: '1px solid rgba(255,255,255,0.06)' }}>\n          <div>\n            <a href=\"/\" onClick={e => { e.preventDefault(); window.scrollTo({ top: 0, behavior: 'smooth' }); }} className=\"text-3xl text-white\" style={{ fontFamily: 'var(--font-display)', letterSpacing: '0.05em', textDecoration: 'none' }}>VOTAAI</a>\n            {votedCount > 0 && <p className=\"text-xs\" style={{ color: 'rgba(255,255,255,0.3)' }}>{votedCount} votos \u2022 \ud83d\udd25 {streak}</p>}\n          </div>\n          <div className=\"flex gap-2 items-center\">\n            {streak >= 3 && <span className=\"text-sm font-bold px-3 py-1 rounded-full\" style={{ background: '#FF6B3520', color: '#FF6B35' }}>\ud83d\udd25{streak}</span>}\n            {isAnon ? (\n              <button onClick={() => setShowAuth(true)} className=\"px-3 py-2 rounded-xl text-xs font-black border\" style={{ borderColor: '#6C63FF66', color: '#6C63FF' }}>Entrar</button>\n            ) : (\n              <div className=\"flex items-center gap-2\">\n                <span className=\"text-xs font-black px-2 py-1 rounded-full\" style={{ background: 'rgba(247,183,49,0.15)', color: '#F7B731' }}>\ud83e\ude99 {votaCoins}</span>\n                <div className=\"w-8 h-8 rounded-full flex items-center justify-center text-xs font-black\" style={{ background: '#6C63FF22', color: '#6C63FF', border: '1px solid #6C63FF44' }}>\n                  {(user?.displayName || user?.email || '?')[0].toUpperCase()}\n                </div>\n              </div>\n            )}\n            <button onClick={() => setShowCreate(true)} className=\"px-4 py-2 rounded-xl text-sm font-black text-white\" style={{ background: '#6C63FF' }}>+ Criar</button>\n          </div>\n        </header>\n\n        {/* Main content */}\n        <main className=\"flex-1 px-4 pt-20 pb-24 md:pt-6 md:pb-6\" style={{ minWidth: 0, width: '100%', maxWidth: 576, boxSizing: 'border-box', margin: '0 auto' }}>\n\n          {/* FEED */}\n          {tab === 'feed' && (\n            <div>\n              {/* Search */}\n              <div className=\"mb-3\">\n                <input\n                  className=\"w-full rounded-2xl px-4 py-3 text-sm text-white outline-none border transition-all\"\n                  style={{ background: 'rgba(255,255,255,0.05)', borderColor: search ? '#6C63FF' : 'rgba(255,255,255,0.08)' }}\n                  placeholder=\"\ud83d\udd0d Buscar enquetes...\"\n                  value={search}\n                  onChange={e => setSearch(e.target.value)}\n                />\n              </div>\n              {/* Category filters */}\n              <div className=\"mb-4\" style={{ display: 'flex', flexWrap: 'wrap', gap: 8, width: '100%' }}>\n                {allTags.map(tag => (\n                  <button\n                    key={tag}\n                    onClick={() => setActiveTag(tag === 'todos' ? null : tag)}\n                    className=\"px-3 py-1.5 rounded-full text-xs font-bold border transition-all capitalize\"\n                    style={{\n                      borderColor: (activeTag === tag || (tag === 'todos' && !activeTag)) ? '#6C63FF' : 'rgba(255,255,255,0.1)',\n                      background: (activeTag === tag || (tag === 'todos' && !activeTag)) ? 'rgba(108,99,255,0.2)' : 'transparent',\n                      color: (activeTag === tag || (tag === 'todos' && !activeTag)) ? '#6C63FF' : 'rgba(255,255,255,0.4)',\n                    }}\n                  >\n                    {tag}\n                  </button>\n                ))}\n              </div>\n              {loading ? (\n                <div className=\"space-y-4\">\n                  {[1,2,3].map(i => (\n                    <div key={i} className=\"rounded-2xl p-6 animate-pulse\" style={{ background: 'rgba(255,255,255,0.03)', height: 200 }} />\n                  ))}\n                </div>\n              ) : (\n                filteredPolls.map((poll, i) => (\n                  <div key={poll.id} ref={el => { pollRefs.current[poll.id] = el; }} style={{ animationDelay: `${i * 0.05}s`, transition: 'box-shadow 0.5s', borderRadius: 16, boxShadow: highlightedId === poll.id ? '0 0 0 3px #FF4E8C, 0 0 30px #FF4E8C44' : 'none' }} className=\"animate-fade-up\">\n                    <PollCard poll={poll} onVote={handleVote} userVote={votes[poll.id]} userId={user?.uid} isFirstVote={!isSubscribed && !!votes[poll.id]} onSubscribed={() => setIsSubscribed(true)} isAnon={isAnon} onShowAuth={() => setShowAuth(true)} />\n\n                    {showCity === poll.id && (\n                      <div className=\"rounded-2xl p-5 mb-4 border\" style={{ background: 'rgba(255,255,255,0.03)', borderColor: 'rgba(255,255,255,0.07)' }}>\n                        <p className=\"text-xs font-bold tracking-widest mb-4\" style={{ color: 'rgba(255,255,255,0.4)' }}>RESULTADO POR CIDADE</p>\n                        <CityMap poll={poll} color={poll.color} />\n                      </div>\n                    )}\n                  </div>\n                ))\n              )}\n              {!loading && filteredPolls.length === 0 && (\n                <div className=\"text-center py-20\" style={{ color: 'rgba(255,255,255,0.3)' }}>\n                  {search || activeTag ? '\ud83d\udd0d Nenhuma enquete encontrada' : 'Nenhuma enquete ainda. Crie a primeira! \ud83d\ude80'}\n                </div>\n              )}\n            </div>\n          )}\n\n          {/* TRENDING */}\n          {tab === 'trending' && (\n            <div>\n              <h2 className=\"text-3xl mb-1 text-white\" style={{ fontFamily: 'var(--font-display)', letterSpacing: '0.05em' }}>TRENDING</h2>\n              <p className=\"text-xs mb-6\" style={{ color: 'rgba(255,255,255,0.3)' }}>Enquetes mais votadas agora</p>\n              {trending.map((poll, i) => {\n                const total = poll.totalVotes || 0;\n                const pctA = total > 0 ? Math.round(((poll.votesA||0) / total) * 100) : 50;\n                const medals = ['\ud83e\udd47','\ud83e\udd48','\ud83e\udd49'];\n                const mColors = ['#F7B731','#AAAAAA','#CD7F32'];\n                const isHot = poll.hotOfDay && i === 0;\n                const pollUrl = poll.slug ? `/p/${poll.slug}` : null;\n                const CardWrapper = ({ children }: { children: React.ReactNode }) => pollUrl ? (\n                  <a href={pollUrl} className=\"flex gap-4 p-5 rounded-2xl mb-3 border block transition-all hover:opacity-80\" style={{ background: isHot ? 'rgba(255,78,140,0.07)' : 'rgba(255,255,255,0.03)', borderColor: isHot ? '#FF4E8C44' : poll.color + '22', textDecoration: 'none' }}>\n                    {children}\n                  </a>\n                ) : (\n                  <div className=\"flex gap-4 p-5 rounded-2xl mb-3 border\" style={{ background: 'rgba(255,255,255,0.03)', borderColor: poll.color + '22' }}>\n                    {children}\n                  </div>\n                );\n                return (\n                  <CardWrapper key={poll.id}>\n                    <div className=\"flex gap-4 flex-1 min-w-0\">\n                      <span className=\"text-2xl font-black shrink-0\" style={{ color: isHot ? '#FF4E8C' : i < 3 ? mColors[i] : 'rgba(255,255,255,0.2)', fontFamily: 'var(--font-display)' }}>\n                        {isHot ? '\ud83d\udd25' : i < 3 ? medals[i] : `#${i+1}`}\n                      </span>\n                      <div className=\"flex-1 min-w-0\">\n                        {isHot && <span className=\"text-xs font-black tracking-widest px-2 py-0.5 rounded-full mb-1 inline-block\" style={{ background: '#FF4E8C22', color: '#FF4E8C' }}>POL\u00caMICA DO DIA</span>}\n                        <p className=\"text-sm font-bold text-white truncate\">{poll.question}</p>\n                        <p className=\"text-xs mt-0.5 truncate\" style={{ color: 'rgba(255,255,255,0.4)' }}>{poll.optionA?.emoji} {poll.optionA?.label} <span style={{ color: 'rgba(255,255,255,0.2)' }}>vs</span> {poll.optionB?.emoji} {poll.optionB?.label}</p>\n                        <div className=\"flex items-center gap-2 mt-2\">\n                          <div className=\"flex-1 h-1.5 rounded-full overflow-hidden\" style={{ background: 'rgba(255,255,255,0.07)' }}>\n                            <div className=\"h-full rounded-full\" style={{ width: `${pctA}%`, background: isHot ? '#FF4E8C' : poll.color }} />\n                          </div>\n                          <span className=\"text-xs font-bold shrink-0\" style={{ color: isHot ? '#FF4E8C' : poll.color }}>{pctA}%</span>\n                        </div>\n                        <p className=\"text-xs mt-1\" style={{ color: 'rgba(255,255,255,0.3)' }}>{fmt(total)} votos</p>\n                      </div>\n                    </div>\n                  </CardWrapper>\n                );\n              })}\n            </div>\n          )}\n\n          {/* PERFIL */}\n          {tab === 'perfil' && (\n            <div>\n              <div className=\"rounded-2xl p-6 mb-4 text-center border\" style={{ background: 'rgba(255,255,255,0.03)', borderColor: '#6C63FF33' }}>\n                <div className=\"w-16 h-16 rounded-full mx-auto mb-3 flex items-center justify-center text-3xl border-2\" style={{ background: '#6C63FF22', borderColor: '#6C63FF' }}>\n                  {isAnon ? '\ud83d\uddf3\ufe0f' : '\ud83d\ude0e'}\n                </div>\n                <p className=\"font-black text-white text-lg\">{user?.displayName || (isAnon ? 'Votante An\u00f4nimo' : user?.email)}</p>\n                <p className=\"text-xs mt-1\" style={{ color: 'rgba(255,255,255,0.3)' }}>{city ? `\ud83d\udccd ${city}` : 'Localiza\u00e7\u00e3o desconhecida'}</p>\n                {isAnon && (\n                  <button onClick={handleGoogleLogin} className=\"mt-4 px-5 py-2 rounded-xl text-sm font-bold border\" style={{ borderColor: '#6C63FF66', color: '#6C63FF' }}>\n                    \ud83d\udd17 Conectar Google\n                  </button>\n                )}\n              </div>\n\n              <div className=\"grid grid-cols-2 gap-3 mb-6\">\n                {[\n                  { label: 'Votos dados', value: votedCount, emoji: '\ud83d\uddf3\ufe0f', color: '#6C63FF' },\n                  { label: 'Streak atual', value: `${streak}\ud83d\udd25`, emoji: '\u26a1', color: '#FF6B35' },\n                  { label: 'Enquetes', value: polls.length, emoji: '\ud83d\udccb', color: '#00C9A7' },\n                  { label: 'Cidade', value: city || '?', emoji: '\ud83d\udccd', color: '#FF4E8C' },\n                ].map(stat => (\n                  <div key={stat.label} className=\"p-4 rounded-2xl text-center border\" style={{ background: 'rgba(255,255,255,0.03)', borderColor: stat.color + '33' }}>\n                    <div className=\"text-2xl mb-2\">{stat.emoji}</div>\n                    <div className=\"text-xl font-black\" style={{ color: stat.color, fontFamily: 'var(--font-display)' }}>{stat.value}</div>\n                    <div className=\"text-xs mt-1\" style={{ color: 'rgba(255,255,255,0.3)' }}>{stat.label}</div>\n                  </div>\n                ))}\n              </div>\n\n              {/* VotaCoins card */}\n              {!isAnon && (\n                <div className=\"rounded-2xl p-5 mb-4 border\" style={{ background: 'rgba(247,183,49,0.05)', borderColor: 'rgba(247,183,49,0.2)' }}>\n                  <div className=\"flex items-center justify-between mb-3\">\n                    <div>\n                      <p className=\"text-xs font-bold tracking-widest\" style={{ color: '#F7B731' }}>\ud83e\ude99 VOTACOINS</p>\n                      <p className=\"text-3xl font-black text-white mt-1\" style={{ fontFamily: 'var(--font-display)' }}>{votaCoins} <span className=\"text-base\" style={{ color: 'rgba(255,255,255,0.4)' }}>= R${(votaCoins * 0.01).toFixed(2)}</span></p>\n                    </div>\n                    <div className=\"text-right\">\n                      <p className=\"text-xs\" style={{ color: 'rgba(255,255,255,0.3)' }}>Saque m\u00edn.</p>\n                      <p className=\"text-sm font-black\" style={{ color: '#F7B731' }}>R$20,00</p>\n                    </div>\n                  </div>\n                  <div className=\"mb-3\">\n                    <div className=\"flex justify-between text-xs mb-1\" style={{ color: 'rgba(255,255,255,0.3)' }}>\n                      <span>{votaCoins} coins</span>\n                      <span>2.000 coins</span>\n                    </div>\n                    <div className=\"h-2 rounded-full overflow-hidden\" style={{ background: 'rgba(255,255,255,0.07)' }}>\n                      <div className=\"h-full rounded-full transition-all\" style={{ width: `${Math.min((votaCoins / 2000) * 100, 100)}%`, background: 'linear-gradient(90deg, #F7B731, #FF6B35)' }} />\n                    </div>\n                  </div>\n                  {votaCoins >= 2000 ? (\n                    <a href={`mailto:vinicius.pessin@gmail.com?subject=Saque VotaCoins&body=Ol\u00e1! Quero sacar meus ${votaCoins} VotaCoins (R$${(votaCoins * 0.01).toFixed(2)}). Meu email: ${user?.email}`}\n                      className=\"w-full py-2.5 rounded-xl text-sm font-black text-center block transition-all\"\n                      style={{ background: 'linear-gradient(90deg, #F7B731, #FF6B35)', color: 'white' }}>\n                      \ud83d\udcb8 Solicitar saque via PIX\n                    </a>\n                  ) : (\n                    <p className=\"text-xs text-center\" style={{ color: 'rgba(255,255,255,0.3)' }}>\n                      Faltam {2000 - votaCoins} coins para sacar \u00b7 Vote mais enquetes!\n                    </p>\n                  )}\n                </div>\n              )}\n\n              <button\n                onClick={() => signOut(auth)}\n                className=\"w-full py-3 rounded-xl text-sm font-bold border mb-6 transition-all hover:bg-white/5\"\n                style={{ borderColor: 'rgba(255,82,82,0.3)', color: '#FF5252' }}\n              >\n                \ud83d\udeaa Sair da conta\n              </button>\n\n              {votedCount > 0 && (\n                <>\n                  <p className=\"text-xs font-bold tracking-widest mb-3\" style={{ color: 'rgba(255,255,255,0.4)' }}>HIST\u00d3RICO DE VOTOS</p>\n                  {Object.entries(votes).map(([id, choice]) => {\n                    const poll = polls.find(p => p.id === id);\n                    if (!poll) return null;\n                    const chosen = choice === 'A' ? poll.optionA : poll.optionB;\n                    return (\n                      <div key={id} className=\"flex items-center gap-3 p-4 rounded-xl mb-2 border\" style={{ background: 'rgba(255,255,255,0.03)', borderColor: 'rgba(255,255,255,0.06)' }}>\n                        <span className=\"text-2xl\">{chosen?.emoji}</span>\n                        <div className=\"flex-1 min-w-0\">\n                          <p className=\"text-sm font-bold text-white truncate\">{chosen?.label}</p>\n                          <p className=\"text-xs truncate\" style={{ color: 'rgba(255,255,255,0.3)' }}>{poll.question}</p>\n                        </div>\n                        <span className=\"text-xs font-black px-2 py-1 rounded-lg border\" style={{ color: poll.color, borderColor: poll.color + '44', background: poll.color + '11' }}>{choice}</span>\n                      </div>\n                    );\n                  })}\n                </>\n              )}\n            </div>\n          )}\n        </main>\n      </div>\n\n      {/* Mobile tab bar */}\n      <div className=\"fixed bottom-0 left-0 right-0 md:hidden flex items-center px-4 pb-safe border-t\" style={{ background: 'rgba(7,7,14,0.97)', backdropFilter: 'blur(20px)', borderColor: 'rgba(255,255,255,0.07)', paddingBottom: 'max(16px, env(safe-area-inset-bottom))' }}>\n        {[\n          { id: 'feed', icon: '\ud83c\udfe0', label: 'Feed' },\n          { id: 'trending', icon: '\ud83d\udcc8', label: 'Trends' },\n          { id: 'perfil', icon: '\ud83d\udc64', label: 'Perfil' },\n        ].map(item => (\n          <button key={item.id} onClick={() => setTab(item.id as any)} className=\"flex-1 flex flex-col items-center py-3 gap-1\">\n            <span className=\"text-xl\">{item.icon}</span>\n            <span className=\"text-xs font-bold\" style={{ color: tab === item.id ? '#6C63FF' : 'rgba(255,255,255,0.3)' }}>{item.label}</span>\n          </button>\n        ))}\n        <button onClick={() => setShowCreate(true)} className=\"px-4 py-2 rounded-xl text-sm font-black text-white ml-2\" style={{ background: '#6C63FF' }}>+ Criar</button>\n      </div>\n\n      {showAuth && (\n        <AuthModal onClose={() => setShowAuth(false)} anonUid={isAnon ? user?.uid : undefined} />\n      )}\n      {showCreate && <CreatePollModal onClose={() => setShowCreate(false)} onCreate={handleCreate} />}\n    </div>\n  );\n}\n\nexport default function Home() { return <HomeCore />; }\n");
fs.writeFileSync('src/app/admin/page.tsx', "'use client';\nimport { useState, useEffect } from 'react';\nimport { collection, getDocs, deleteDoc, doc, orderBy, query, updateDoc, setDoc, getDoc } from 'firebase/firestore';\nimport { db, auth } from '@/lib/firebase';\nimport { onAuthStateChanged, User } from 'firebase/auth';\nimport { signInWithGoogle } from '@/lib/polls';\n\nconst ADMIN_EMAIL = 'vinicius.pessin@gmail.com';\nconst DEFAULT_TAGS = ['comida','vida','esporte','estilo de vida','rotina','superpoderes','trabalho','tecnologia','entretenimento','outro'];\n\nfunction fmt(n: number) {\n  if (n >= 1000) return (n / 1000).toFixed(1) + 'k';\n  return String(n || 0);\n}\n\nexport default function AdminPage() {\n  const [user, setUser] = useState<User | null>(null);\n  const [polls, setPolls] = useState<any[]>([]);\n  const [loading, setLoading] = useState(true);\n  const [deleting, setDeleting] = useState<string | null>(null);\n  const [search, setSearch] = useState('');\n  const [sortBy, setSortBy] = useState<'order' | 'popular'>('order');\n  const [toast, setToast] = useState<string | null>(null);\n  const [activeTab, setActiveTab] = useState<'polls' | 'categories' | 'whatsapp' | 'members'>('polls');\n  const [categories, setCategories] = useState<string[]>(DEFAULT_TAGS);\n  const [newCat, setNewCat] = useState('');\n  const [savingCat, setSavingCat] = useState(false);\n  const [subscribers, setSubscribers] = useState<any[]>([]);\n  const [members, setMembers] = useState<any[]>([]);\n\n  useEffect(() => {\n    const unsub = onAuthStateChanged(auth, u => { setUser(u); setLoading(false); });\n    return unsub;\n  }, []);\n\n  useEffect(() => {\n    if (user?.email === ADMIN_EMAIL) {\n      fetchPolls();\n      fetchCategories();\n      fetchSubscribers();\n      fetchMembers();\n    }\n  }, [user]);\n\n  const fetchPolls = async () => {\n    const q = query(collection(db, 'polls'), orderBy('createdAt', 'desc'));\n    const snap = await getDocs(q);\n    const data = snap.docs.map((d, i) => ({ id: d.id, ...d.data(), _order: (d.data() as any).order ?? i }));\n    setPolls(data.sort((a, b) => a._order - b._order));\n  };\n\n  const fetchCategories = async () => {\n    try {\n      const snap = await getDoc(doc(db, 'config', 'categories'));\n      if (snap.exists()) setCategories(snap.data().list || DEFAULT_TAGS);\n    } catch { setCategories(DEFAULT_TAGS); }\n  };\n\n  const fetchSubscribers = async () => {\n    const snap = await getDocs(collection(db, 'subscribers'));\n    setSubscribers(snap.docs.map(d => ({ id: d.id, ...d.data() })).filter((s: any) => s.active));\n  };\n\n  const fetchMembers = async () => {\n    const snap = await getDocs(collection(db, 'members'));\n    const list = snap.docs.map(d => ({ id: d.id, ...d.data() }));\n    setMembers(list.sort((a: any, b: any) => new Date(b.joinedAt || 0).getTime() - new Date(a.joinedAt || 0).getTime()));\n  };\n\n  const showToast = (msg: string) => { setToast(msg); setTimeout(() => setToast(null), 3000); };\n\n  const handleDelete = async (id: string, question: string) => {\n    if (!confirm(`Deletar enquete?\\n\\n\"${question}\"\\n\\nEsta a\u00e7\u00e3o n\u00e3o pode ser desfeita.`)) return;\n    setDeleting(id);\n    await deleteDoc(doc(db, 'polls', id));\n    setPolls(p => p.filter(x => x.id !== id));\n    setDeleting(null);\n    showToast('\ud83d\uddd1\ufe0f Enquete deletada!');\n  };\n\n  const handlePin = async (id: string, pinned: boolean) => {\n    await updateDoc(doc(db, 'polls', id), { pinned: !pinned });\n    setPolls(p => p.map(x => x.id === id ? { ...x, pinned: !pinned } : x));\n    showToast(pinned ? '\ud83d\udccc Enquete desafixada' : '\ud83d\udccc Enquete fixada no topo!');\n  };\n\n  const handleHotOfDay = async (id: string, current: boolean) => {\n    if (!current) {\n      const toRemove = polls.filter(p => p.hotOfDay && p.id !== id);\n      await Promise.all(toRemove.map(p => updateDoc(doc(db, 'polls', p.id), { hotOfDay: false })));\n    }\n    await updateDoc(doc(db, 'polls', id), { hotOfDay: !current });\n    setPolls(p => p.map(x => ({ ...x, hotOfDay: x.id === id ? !current : (!current ? false : x.hotOfDay) })));\n    showToast(!current ? '\ud83d\udd25 Pol\u00eamica do Dia definida!' : '\ud83d\udd25 Selo removido');\n  };\n\n  const handleMove = async (index: number, direction: 'up' | 'down') => {\n    const newPolls = [...polls];\n    const swapIndex = direction === 'up' ? index - 1 : index + 1;\n    if (swapIndex < 0 || swapIndex >= newPolls.length) return;\n    [newPolls[index], newPolls[swapIndex]] = [newPolls[swapIndex], newPolls[index]];\n    setPolls(newPolls);\n    await Promise.all([\n      updateDoc(doc(db, 'polls', newPolls[index].id), { order: index }),\n      updateDoc(doc(db, 'polls', newPolls[swapIndex].id), { order: swapIndex }),\n    ]);\n    showToast('\u2195\ufe0f Ordem atualizada!');\n  };\n\n  const handleAddCategory = async () => {\n    const cat = newCat.trim().toLowerCase();\n    if (!cat || categories.includes(cat)) return;\n    setSavingCat(true);\n    const updated = [...categories, cat];\n    await setDoc(doc(db, 'config', 'categories'), { list: updated });\n    setCategories(updated);\n    setNewCat('');\n    setSavingCat(false);\n    showToast(`\u2705 Categoria \"${cat}\" criada!`);\n  };\n\n  const handleDeleteCategory = async (cat: string) => {\n    if (DEFAULT_TAGS.includes(cat)) return showToast('\u26a0\ufe0f N\u00e3o \u00e9 poss\u00edvel deletar categorias padr\u00e3o');\n    const updated = categories.filter(c => c !== cat);\n    await setDoc(doc(db, 'config', 'categories'), { list: updated });\n    setCategories(updated);\n    showToast(`\ud83d\uddd1\ufe0f Categoria \"${cat}\" removida`);\n  };\n\n  const exportMembersCSV = () => {\n    const csv = [\n      'Email,Data de cadastro,Votos,Provedor',\n      ...members.map((m: any) => `${m.email},${m.joinedAt ? new Date(m.joinedAt).toLocaleDateString('pt-BR') : '-'},${m.voteCount},${m.provider === 'google.com' ? 'Google' : 'Email'}`)\n    ].join('\\n');\n    const blob = new Blob([csv], { type: 'text/csv' });\n    const url = URL.createObjectURL(blob);\n    const a = document.createElement('a');\n    a.href = url; a.download = 'membros-votaai.csv'; a.click();\n    URL.revokeObjectURL(url);\n  };\n\n  if (loading) return (\n    <div className=\"min-h-screen flex items-center justify-center\" style={{ background: '#07070E' }}>\n      <div className=\"text-white/40 text-sm\">Carregando...</div>\n    </div>\n  );\n\n  const isAdmin = user?.email === ADMIN_EMAIL;\n  const filtered = polls\n    .filter(p => p.question?.toLowerCase().includes(search.toLowerCase()) ||\n      p.optionA?.label?.toLowerCase().includes(search.toLowerCase()) ||\n      p.optionB?.label?.toLowerCase().includes(search.toLowerCase()))\n    .sort((a, b) => sortBy === 'popular' ? (b.totalVotes || 0) - (a.totalVotes || 0) : (a._order - b._order));\n  const totalVotes = polls.reduce((acc, p) => acc + (p.totalVotes || 0), 0);\n  const hotPoll = polls.find(p => p.hotOfDay);\n\n  return (\n    <div className=\"min-h-screen\" style={{ background: '#07070E' }}>\n      {toast && (\n        <div className=\"fixed top-4 left-1/2 -translate-x-1/2 z-50 px-5 py-3 rounded-2xl text-white font-bold text-sm shadow-2xl\" style={{ background: '#6C63FF' }}>\n          {toast}\n        </div>\n      )}\n\n      <div className=\"border-b px-6 py-4 flex items-center justify-between\" style={{ borderColor: 'rgba(255,255,255,0.07)', background: 'rgba(255,255,255,0.02)' }}>\n        <div className=\"flex items-center gap-3\">\n          <a href=\"/\" className=\"text-sm font-bold\" style={{ color: 'rgba(255,255,255,0.4)' }}>\u2190 VotaA\u00ed</a>\n          <span style={{ color: 'rgba(255,255,255,0.15)' }}>/</span>\n          <h1 className=\"text-lg font-black text-white\" style={{ fontFamily: 'var(--font-display)', letterSpacing: '0.05em' }}>ADMIN</h1>\n        </div>\n        {isAdmin && <span className=\"text-xs px-3 py-1 rounded-full\" style={{ background: 'rgba(0,201,167,0.15)', color: '#00C9A7' }}>\u2705 {user?.email}</span>}\n      </div>\n\n      {!isAdmin ? (\n        <div className=\"min-h-screen flex items-center justify-center p-4\">\n          <div className=\"text-center max-w-sm\">\n            <div className=\"text-6xl mb-6\">\ud83d\udd12</div>\n            <h1 className=\"text-2xl font-black text-white mb-2\" style={{ fontFamily: 'var(--font-display)', letterSpacing: '0.05em' }}>ACESSO RESTRITO</h1>\n            <p className=\"text-sm mb-8\" style={{ color: 'rgba(255,255,255,0.4)' }}>Essa p\u00e1gina \u00e9 exclusiva para administradores.</p>\n            {user && <p className=\"text-xs mb-4 px-4 py-2 rounded-xl\" style={{ background: 'rgba(255,82,82,0.15)', color: '#FF5252' }}>Logado como {user.email} \u2014 sem permiss\u00e3o</p>}\n            <button onClick={signInWithGoogle} className=\"px-6 py-3 rounded-xl font-black text-white text-sm\" style={{ background: '#6C63FF' }}>\ud83d\udd17 Entrar com Google</button>\n            <a href=\"/\" className=\"block mt-4 text-sm\" style={{ color: 'rgba(255,255,255,0.3)' }}>\u2190 Voltar ao site</a>\n          </div>\n        </div>\n      ) : (\n        <div className=\"max-w-4xl mx-auto p-6\">\n\n          {/* Stats */}\n          <div className=\"grid grid-cols-4 gap-4 mb-6\">\n            {[\n              { label: 'Enquetes', value: polls.length, emoji: '\ud83d\udccb', color: '#6C63FF' },\n              { label: 'Votos totais', value: fmt(totalVotes), emoji: '\ud83d\uddf3\ufe0f', color: '#00C9A7' },\n              { label: 'Membros', value: members.length, emoji: '\ud83d\udc65', color: '#FF4E8C' },\n              { label: 'Inscritos ZAP', value: subscribers.length, emoji: '\ud83d\udcac', color: '#25D366' },\n            ].map(s => (\n              <div key={s.label} className=\"rounded-2xl p-4 border text-center\" style={{ background: 'rgba(255,255,255,0.03)', borderColor: s.color + '33' }}>\n                <div className=\"text-xl mb-1\">{s.emoji}</div>\n                <div className=\"text-xl font-black\" style={{ color: s.color, fontFamily: 'var(--font-display)' }}>{s.value}</div>\n                <div className=\"text-xs mt-0.5\" style={{ color: 'rgba(255,255,255,0.3)' }}>{s.label}</div>\n              </div>\n            ))}\n          </div>\n\n          {/* Tabs */}\n          <div className=\"flex gap-2 mb-6 flex-wrap\">\n            {[\n              { id: 'polls', label: '\ud83d\udccb Enquetes' },\n              { id: 'members', label: '\ud83d\udc65 Membros' },\n              { id: 'whatsapp', label: '\ud83d\udcac WhatsApp' },\n              { id: 'categories', label: '\ud83c\udff7\ufe0f Categorias' },\n            ].map(t => (\n              <button key={t.id} onClick={() => setActiveTab(t.id as any)} className=\"px-5 py-2.5 rounded-xl text-sm font-bold transition-all\" style={{ background: activeTab === t.id ? '#6C63FF' : 'rgba(255,255,255,0.05)', color: activeTab === t.id ? 'white' : 'rgba(255,255,255,0.4)' }}>\n                {t.label}\n              </button>\n            ))}\n          </div>\n\n          {/* POLLS TAB */}\n          {activeTab === 'polls' && (\n            <>\n              <div className=\"flex gap-3 mb-6\">\n                <input className=\"flex-1 rounded-xl px-4 py-3 text-sm text-white outline-none border\" style={{ background: 'rgba(255,255,255,0.05)', borderColor: 'rgba(255,255,255,0.1)' }} placeholder=\"\ud83d\udd0d Buscar enquetes...\" value={search} onChange={e => setSearch(e.target.value)} />\n                <button onClick={() => setSortBy(s => s === 'order' ? 'popular' : 'order')} className=\"px-4 py-3 rounded-xl text-sm font-bold border\" style={{ borderColor: 'rgba(255,255,255,0.1)', color: 'rgba(255,255,255,0.5)', background: 'rgba(255,255,255,0.03)' }}>\n                  {sortBy === 'order' ? '\u2195\ufe0f Ordem' : '\ud83d\udcc8 Populares'}\n                </button>\n                <button onClick={fetchPolls} className=\"px-4 py-3 rounded-xl text-sm font-bold border\" style={{ borderColor: 'rgba(255,255,255,0.1)', color: 'rgba(255,255,255,0.5)', background: 'rgba(255,255,255,0.03)' }}>\ud83d\udd04</button>\n              </div>\n              <div className=\"space-y-3\">\n                {filtered.map((poll) => {\n                  const total = poll.totalVotes || 0;\n                  const pctA = total > 0 ? Math.round(((poll.votesA || 0) / total) * 100) : 50;\n                  const realIndex = polls.findIndex(p => p.id === poll.id);\n                  return (\n                    <div key={poll.id} className=\"rounded-2xl p-5 border transition-all\" style={{ background: poll.pinned ? 'rgba(247,183,49,0.05)' : 'rgba(255,255,255,0.03)', borderColor: poll.hotOfDay ? '#FF4E8C33' : poll.pinned ? '#F7B73133' : 'rgba(255,255,255,0.07)' }}>\n                      <div className=\"flex items-start gap-4\">\n                        {sortBy === 'order' && (\n                          <div className=\"flex flex-col gap-1 shrink-0 mt-1\">\n                            <button onClick={() => handleMove(realIndex, 'up')} disabled={realIndex === 0} className=\"w-7 h-7 rounded-lg flex items-center justify-center text-xs\" style={{ background: 'rgba(255,255,255,0.06)', color: realIndex === 0 ? 'rgba(255,255,255,0.15)' : 'rgba(255,255,255,0.6)' }}>\u25b2</button>\n                            <div className=\"text-center text-xs font-bold\" style={{ color: 'rgba(255,255,255,0.2)' }}>{realIndex + 1}</div>\n                            <button onClick={() => handleMove(realIndex, 'down')} disabled={realIndex === polls.length - 1} className=\"w-7 h-7 rounded-lg flex items-center justify-center text-xs\" style={{ background: 'rgba(255,255,255,0.06)', color: realIndex === polls.length - 1 ? 'rgba(255,255,255,0.15)' : 'rgba(255,255,255,0.6)' }}>\u25bc</button>\n                          </div>\n                        )}\n                        <div className=\"w-3 h-3 rounded-full mt-1.5 shrink-0\" style={{ background: poll.color || '#6C63FF' }} />\n                        <div className=\"flex-1 min-w-0\">\n                          <div className=\"flex items-center gap-2 mb-1 flex-wrap\">\n                            {poll.hotOfDay && <span className=\"text-xs px-2 py-0.5 rounded-full font-bold\" style={{ background: '#FF4E8C22', color: '#FF4E8C' }}>\ud83d\udd25 Pol\u00eamica do Dia</span>}\n                            {poll.pinned && <span className=\"text-xs px-2 py-0.5 rounded-full font-bold\" style={{ background: '#F7B73122', color: '#F7B731' }}>\ud83d\udccc Fixada</span>}\n                            <span className=\"text-xs font-bold tracking-widest uppercase\" style={{ color: 'rgba(255,255,255,0.3)' }}>{poll.tag}</span>\n                          </div>\n                          <p className=\"text-white font-bold text-sm mb-2\">{poll.question}</p>\n                          <div className=\"flex items-center gap-3 text-xs mb-3\" style={{ color: 'rgba(255,255,255,0.4)' }}>\n                            <span>{poll.optionA?.emoji} {poll.optionA?.label}</span>\n                            <span style={{ color: 'rgba(255,255,255,0.2)' }}>vs</span>\n                            <span>{poll.optionB?.emoji} {poll.optionB?.label}</span>\n                          </div>\n                          <div className=\"flex items-center gap-2\">\n                            <span className=\"text-xs font-bold\" style={{ color: poll.color || '#6C63FF', minWidth: 32 }}>{pctA}%</span>\n                            <div className=\"flex-1 h-1.5 rounded-full overflow-hidden\" style={{ background: 'rgba(255,255,255,0.07)' }}>\n                              <div className=\"h-full rounded-full\" style={{ width: `${pctA}%`, background: poll.color || '#6C63FF' }} />\n                            </div>\n                            <span className=\"text-xs font-bold\" style={{ color: 'rgba(255,255,255,0.3)', minWidth: 32, textAlign: 'right' }}>{100 - pctA}%</span>\n                            <span className=\"text-xs ml-2\" style={{ color: 'rgba(255,255,255,0.25)' }}>{fmt(total)} votos</span>\n                          </div>\n                        </div>\n                        <div className=\"flex flex-col gap-2 shrink-0\">\n                          <button onClick={() => handleHotOfDay(poll.id, !!poll.hotOfDay)} className=\"px-3 py-1.5 rounded-lg text-xs font-bold border transition-all\" style={{ borderColor: poll.hotOfDay ? '#FF4E8C44' : 'rgba(255,255,255,0.1)', color: poll.hotOfDay ? '#FF4E8C' : 'rgba(255,255,255,0.4)', background: poll.hotOfDay ? '#FF4E8C11' : 'transparent' }}>\n                            {poll.hotOfDay ? '\ud83d\udd25 Ativa' : '\ud83d\udd25 Setar'}\n                          </button>\n                          <button onClick={() => handlePin(poll.id, poll.pinned)} className=\"px-3 py-1.5 rounded-lg text-xs font-bold border transition-all\" style={{ borderColor: poll.pinned ? '#F7B73144' : 'rgba(255,255,255,0.1)', color: poll.pinned ? '#F7B731' : 'rgba(255,255,255,0.4)', background: poll.pinned ? '#F7B73111' : 'transparent' }}>\n                            {poll.pinned ? '\ud83d\udccc Fixada' : '\ud83d\udccc Fixar'}\n                          </button>\n                          <button onClick={() => handleDelete(poll.id, poll.question)} disabled={deleting === poll.id} className=\"px-3 py-1.5 rounded-lg text-xs font-bold border\" style={{ borderColor: '#FF525233', color: '#FF5252', background: 'rgba(255,82,82,0.07)' }}>\n                            {deleting === poll.id ? '...' : '\ud83d\uddd1\ufe0f Deletar'}\n                          </button>\n                        </div>\n                      </div>\n                    </div>\n                  );\n                })}\n                {filtered.length === 0 && <div className=\"text-center py-16\" style={{ color: 'rgba(255,255,255,0.3)' }}>Nenhuma enquete encontrada</div>}\n              </div>\n            </>\n          )}\n\n          {/* MEMBERS TAB */}\n          {activeTab === 'members' && (\n            <div>\n              <div className=\"flex items-center justify-between mb-6\">\n                <div>\n                  <p className=\"text-white font-black text-lg\">{members.length} membros</p>\n                  <p className=\"text-xs mt-1\" style={{ color: 'rgba(255,255,255,0.4)' }}>Usu\u00e1rios com conta cadastrada</p>\n                </div>\n                <div className=\"flex gap-2\">\n                  <button onClick={fetchMembers} className=\"px-4 py-2 rounded-xl text-sm font-bold border\" style={{ borderColor: 'rgba(255,255,255,0.1)', color: 'rgba(255,255,255,0.5)', background: 'rgba(255,255,255,0.03)' }}>\ud83d\udd04</button>\n                  <button onClick={exportMembersCSV} className=\"px-4 py-2 rounded-xl text-sm font-bold border\" style={{ borderColor: '#00C9A733', color: '#00C9A7', background: 'rgba(0,201,167,0.07)' }}>\n                    \ud83d\udce5 Exportar CSV\n                  </button>\n                </div>\n              </div>\n              <div className=\"space-y-2\">\n                {members.map((m: any) => (\n                  <div key={m.id} className=\"flex items-center gap-4 p-4 rounded-xl border\" style={{ background: 'rgba(255,255,255,0.03)', borderColor: 'rgba(255,255,255,0.07)' }}>\n                    <div className=\"w-9 h-9 rounded-full flex items-center justify-center font-black text-sm shrink-0\" style={{ background: m.provider === 'google.com' ? '#4285F422' : '#6C63FF22', color: m.provider === 'google.com' ? '#4285F4' : '#6C63FF' }}>\n                      {(m.email || '?')[0].toUpperCase()}\n                    </div>\n                    <div className=\"flex-1 min-w-0\">\n                      <p className=\"text-sm font-bold text-white truncate\">{m.email}</p>\n                      <p className=\"text-xs mt-0.5\" style={{ color: 'rgba(255,255,255,0.3)' }}>\n                        {m.provider === 'google.com' ? '\ud83d\udd35 Google' : '\ud83d\udce7 Email'} \u00b7 {m.joinedAt ? new Date(m.joinedAt).toLocaleDateString('pt-BR') : '-'}\n                      </p>\n                    </div>\n                    <div className=\"text-right shrink-0\">\n                      <p className=\"text-sm font-black\" style={{ color: '#6C63FF' }}>{m.voteCount}</p>\n                      <p className=\"text-xs\" style={{ color: 'rgba(255,255,255,0.3)' }}>votos</p>\n                    </div>\n                  </div>\n                ))}\n                {members.length === 0 && <p className=\"text-center py-16 text-sm\" style={{ color: 'rgba(255,255,255,0.3)' }}>Nenhum membro ainda</p>}\n              </div>\n            </div>\n          )}\n\n          {/* WHATSAPP TAB */}\n          {activeTab === 'whatsapp' && (\n            <div>\n              <div className=\"flex items-center justify-between mb-6\">\n                <div>\n                  <p className=\"text-white font-black text-lg\">{subscribers.length} inscritos</p>\n                  <p className=\"text-xs mt-1\" style={{ color: 'rgba(255,255,255,0.4)' }}>Recebem a Pol\u00eamica do Dia no WhatsApp</p>\n                </div>\n                <button onClick={fetchSubscribers} className=\"px-4 py-2 rounded-xl text-sm font-bold border\" style={{ borderColor: 'rgba(255,255,255,0.1)', color: 'rgba(255,255,255,0.5)', background: 'rgba(255,255,255,0.03)' }}>\ud83d\udd04</button>\n              </div>\n              {!hotPoll ? (\n                <div className=\"p-4 rounded-xl mb-6 text-sm text-center\" style={{ background: 'rgba(255,82,82,0.1)', color: '#FF5252', border: '1px solid #FF525233' }}>\n                  \u26a0\ufe0f Defina uma Pol\u00eamica do Dia antes de disparar\n                </div>\n              ) : (\n                <div className=\"p-4 rounded-xl mb-6 border\" style={{ background: 'rgba(247,183,49,0.05)', borderColor: '#F7B73133' }}>\n                  <p className=\"text-xs font-bold tracking-widest mb-2\" style={{ color: '#F7B731' }}>\ud83d\udd25 POL\u00caMICA DO DIA ATIVA</p>\n                  <p className=\"text-white font-bold text-sm mb-1\">{hotPoll.question}</p>\n                  <p className=\"text-xs mb-4\" style={{ color: 'rgba(255,255,255,0.4)' }}>Clique em cada contato para abrir o WhatsApp e enviar.</p>\n                  <div className=\"space-y-2 max-h-96 overflow-y-auto\">\n                    {subscribers.map((s: any) => {\n                      const msg = encodeURIComponent(`\ud83d\udd25 POL\u00caMICA DO DIA no VotaA\u00ed!\\n${hotPoll.question}\\nhttps://votaai.app\\nResponda SAIR para cancelar`);\n                      return (\n                        <a key={s.id} href={`https://wa.me/55${s.phone}?text=${msg}`} target=\"_blank\" rel=\"noopener noreferrer\" className=\"flex items-center justify-between p-3 rounded-xl border transition-all\" style={{ background: 'rgba(37,211,102,0.05)', borderColor: '#25D36633' }}>\n                          <div>\n                            <p className=\"text-sm font-bold text-white\">{s.name || 'An\u00f4nimo'}</p>\n                            <p className=\"text-xs\" style={{ color: 'rgba(255,255,255,0.3)' }}>+55 {s.phone}</p>\n                          </div>\n                          <span className=\"text-lg\">\ud83d\udcac</span>\n                        </a>\n                      );\n                    })}\n                    {subscribers.length === 0 && <p className=\"text-center text-sm py-4\" style={{ color: 'rgba(255,255,255,0.3)' }}>Nenhum inscrito ainda</p>}\n                  </div>\n                </div>\n              )}\n            </div>\n          )}\n\n          {/* CATEGORIES TAB */}\n          {activeTab === 'categories' && (\n            <div>\n              <p className=\"text-sm mb-6\" style={{ color: 'rgba(255,255,255,0.4)' }}>Categorias aparecem no modal de cria\u00e7\u00e3o de enquetes. As categorias padr\u00e3o n\u00e3o podem ser removidas.</p>\n              <div className=\"flex gap-3 mb-6\">\n                <input className=\"flex-1 rounded-xl px-4 py-3 text-sm text-white outline-none border\" style={{ background: 'rgba(255,255,255,0.05)', borderColor: 'rgba(255,255,255,0.1)' }} placeholder=\"Nova categoria...\" value={newCat} onChange={e => setNewCat(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleAddCategory()} />\n                <button onClick={handleAddCategory} disabled={!newCat.trim() || savingCat} className=\"px-5 py-3 rounded-xl text-sm font-black transition-all\" style={{ background: newCat.trim() ? '#6C63FF' : 'rgba(255,255,255,0.07)', color: newCat.trim() ? 'white' : 'rgba(255,255,255,0.3)' }}>\n                  {savingCat ? '...' : '+ Adicionar'}\n                </button>\n              </div>\n              <div className=\"grid grid-cols-2 gap-3\">\n                {categories.map(cat => {\n                  const isDefault = DEFAULT_TAGS.includes(cat);\n                  const pollCount = polls.filter(p => p.tag === cat).length;\n                  return (\n                    <div key={cat} className=\"flex items-center justify-between p-4 rounded-xl border\" style={{ background: 'rgba(255,255,255,0.03)', borderColor: 'rgba(255,255,255,0.07)' }}>\n                      <div>\n                        <p className=\"text-sm font-bold text-white capitalize\">{cat}</p>\n                        <p className=\"text-xs mt-0.5\" style={{ color: 'rgba(255,255,255,0.3)' }}>{pollCount} enquete{pollCount !== 1 ? 's' : ''}</p>\n                      </div>\n                      <div className=\"flex items-center gap-2\">\n                        {isDefault && <span className=\"text-xs px-2 py-0.5 rounded-full\" style={{ background: 'rgba(255,255,255,0.07)', color: 'rgba(255,255,255,0.3)' }}>padr\u00e3o</span>}\n                        {!isDefault && <button onClick={() => handleDeleteCategory(cat)} className=\"w-7 h-7 rounded-lg flex items-center justify-center text-xs\" style={{ background: 'rgba(255,82,82,0.1)', color: '#FF5252' }}>\u2715</button>}\n                      </div>\n                    </div>\n                  );\n                })}\n              </div>\n            </div>\n          )}\n        </div>\n      )}\n    </div>\n  );\n}\n");
fs.writeFileSync('src/components/AuthModal.tsx', "'use client';\nimport { useState } from 'react';\nimport {\n  GoogleAuthProvider, signInWithPopup, signInWithEmailAndPassword,\n  linkWithCredential, EmailAuthProvider, User,\n} from 'firebase/auth';\nimport { auth, db } from '@/lib/firebase';\nimport { doc, getDocs, collection, setDoc, deleteDoc, increment } from 'firebase/firestore';\n\ntype Mode = 'choose' | 'login' | 'register';\n\nconst WELCOME_BONUS = 50;\nconst SAQUE_MINIMO = 2000;\n\nconst saveMemberProfile = async (u: User | null, phone?: string, isNew?: boolean) => {\n  if (!u || u.isAnonymous || !u.email) return;\n  const data: any = {\n    email: u.email,\n    displayName: u.displayName || null,\n    provider: u.providerData?.[0]?.providerId || 'password',\n    joinedAt: u.metadata?.creationTime || null,\n    lastLogin: new Date().toISOString(),\n    uid: u.uid,\n  };\n  if (phone) data.phone = phone.replace(/\\D/g, '');\n  if (isNew) data.votaCoins = increment(WELCOME_BONUS);\n  await setDoc(doc(db, 'members', u.uid), data, { merge: true })\n    .catch(e => console.error('members write error:', e));\n\n  // Also save to subscribers if phone provided\n  if (phone) {\n    const cleanPhone = phone.replace(/\\D/g, '');\n    await setDoc(doc(db, 'subscribers', u.uid), {\n      phone: cleanPhone,\n      name: u.displayName || u.email,\n      userId: u.uid,\n      active: true,\n      joinedAt: new Date().toISOString(),\n    }, { merge: true }).catch(() => null);\n  }\n};\n\nconst migrateVotes = async (fromUid: string, toUid: string) => {\n  try {\n    const snap = await getDocs(collection(db, `users/${fromUid}/votes`));\n    await Promise.all(snap.docs.map(d =>\n      setDoc(doc(db, `users/${toUid}/votes/${d.id}`), d.data())\n    ));\n    const subSnap = await getDocs(collection(db, 'subscribers'));\n    const sub = subSnap.docs.find(d => d.id === fromUid);\n    if (sub) {\n      await setDoc(doc(db, 'subscribers', toUid), { ...sub.data(), userId: toUid });\n      await deleteDoc(doc(db, 'subscribers', fromUid));\n    }\n  } catch (e) {\n    console.error('migrate error', e);\n  }\n};\n\nexport default function AuthModal({ onClose, anonUid }: {\n  onClose: () => void;\n  anonUid?: string;\n}) {\n  const [mode, setMode] = useState<Mode>('choose');\n  const [email, setEmail] = useState('');\n  const [password, setPassword] = useState('');\n  const [phone, setPhone] = useState('');\n  const [loading, setLoading] = useState(false);\n  const [error, setError] = useState('');\n\n  const handleGoogle = async () => {\n    setLoading(true);\n    setError('');\n    try {\n      const provider = new GoogleAuthProvider();\n      const currentUser = auth.currentUser;\n      let isNew = false;\n      if (currentUser?.isAnonymous) {\n        try {\n          const result = await signInWithPopup(auth, provider);\n          const credential = GoogleAuthProvider.credentialFromResult(result);\n          if (credential) await linkWithCredential(currentUser, credential);\n          isNew = true;\n        } catch (linkErr: any) {\n          if (linkErr.code === 'auth/credential-already-in-use') {\n            const result = await signInWithPopup(auth, provider);\n            if (anonUid && anonUid !== result.user.uid) await migrateVotes(anonUid, result.user.uid);\n          } else if (linkErr.code !== 'auth/popup-closed-by-user') {\n            throw linkErr;\n          }\n        }\n      } else {\n        await signInWithPopup(auth, provider);\n      }\n      await saveMemberProfile(auth.currentUser, phone || undefined, isNew);\n      onClose();\n    } catch (e: any) {\n      if (e.code !== 'auth/popup-closed-by-user') setError('Erro ao entrar com Google.');\n    }\n    setLoading(false);\n  };\n\n  const handleEmailAuth = async () => {\n    if (!email || password.length < 6) {\n      setError('Email v\u00e1lido e senha com m\u00ednimo 6 caracteres.');\n      return;\n    }\n    setLoading(true);\n    setError('');\n    try {\n      const currentUser = auth.currentUser;\n      const credential = EmailAuthProvider.credential(email, password);\n      let isNew = false;\n\n      if (mode === 'register') {\n        if (currentUser?.isAnonymous) {\n          try {\n            await linkWithCredential(currentUser, credential);\n            isNew = true;\n          } catch (linkErr: any) {\n            if (linkErr.code === 'auth/email-already-in-use') {\n              setError('Este email j\u00e1 est\u00e1 cadastrado. Tente fazer login.');\n              setLoading(false);\n              return;\n            }\n            throw linkErr;\n          }\n        } else {\n          const { createUserWithEmailAndPassword } = await import('firebase/auth');\n          await createUserWithEmailAndPassword(auth, email, password);\n          isNew = true;\n        }\n      } else {\n        const prevUid = currentUser?.isAnonymous ? anonUid : undefined;\n        const result = await signInWithEmailAndPassword(auth, email, password);\n        if (prevUid && prevUid !== result.user.uid) await migrateVotes(prevUid, result.user.uid);\n      }\n      await saveMemberProfile(auth.currentUser, phone || undefined, isNew);\n      onClose();\n    } catch (e: any) {\n      if (e.code === 'auth/user-not-found' || e.code === 'auth/wrong-password' || e.code === 'auth/invalid-credential') {\n        setError('Email ou senha incorretos.');\n      } else if (e.code === 'auth/email-already-in-use') {\n        setError('Email j\u00e1 cadastrado. Fa\u00e7a login.');\n      } else if (e.code === 'auth/invalid-email') {\n        setError('Email inv\u00e1lido.');\n      } else {\n        setError('Erro inesperado. Tente novamente.');\n      }\n    }\n    setLoading(false);\n  };\n\n  return (\n    <div className=\"fixed inset-0 z-50 flex items-end sm:items-center justify-center p-4\">\n      <div className=\"absolute inset-0 bg-black/70 backdrop-blur-sm\" onClick={onClose} />\n      <div className=\"relative w-full max-w-sm rounded-2xl p-6 border\" style={{ background: '#13131A', borderColor: 'rgba(255,255,255,0.1)' }}>\n\n        <div className=\"flex items-center justify-between mb-6\">\n          <div>\n            {mode !== 'choose' && (\n              <button onClick={() => { setMode('choose'); setError(''); }} className=\"text-xs mb-1 flex items-center gap-1\" style={{ color: 'rgba(255,255,255,0.4)' }}>\n                \u2190 Voltar\n              </button>\n            )}\n            <h2 className=\"text-xl font-black text-white\" style={{ fontFamily: 'var(--font-display)', letterSpacing: '0.05em' }}>\n              {mode === 'choose' ? 'ENTRAR' : mode === 'login' ? 'LOGIN' : 'CADASTRO'}\n            </h2>\n            <p className=\"text-xs mt-0.5\" style={{ color: 'rgba(255,255,255,0.4)' }}>\n              {mode === 'register'\n                ? `\ud83e\ude99 Ganhe ${WELCOME_BONUS} VotaCoins de boas-vindas!`\n                : mode === 'login' ? 'Entre na sua conta'\n                : 'Vote e ganhe VotaCoins'}\n            </p>\n          </div>\n          <button onClick={onClose} className=\"w-7 h-7 rounded-full flex items-center justify-center text-xs\" style={{ background: 'rgba(255,255,255,0.07)', color: 'rgba(255,255,255,0.4)' }}>\u2715</button>\n        </div>\n\n        {mode === 'choose' && (\n          <div className=\"space-y-3\">\n            {/* VotaCoins banner */}\n            <div className=\"p-3 rounded-xl text-center mb-1\" style={{ background: 'rgba(247,183,49,0.08)', border: '1px solid rgba(247,183,49,0.2)' }}>\n              <p className=\"text-xs font-bold\" style={{ color: '#F7B731' }}>\ud83e\ude99 Ganhe VotaCoins votando!</p>\n              <p className=\"text-xs mt-0.5\" style={{ color: 'rgba(255,255,255,0.4)' }}>1 voto = 1 VotaCoin = R$0,01 \u00b7 Saque m\u00edn. R${SAQUE_MINIMO / 100}</p>\n            </div>\n            <button onClick={handleGoogle} disabled={loading} className=\"w-full flex items-center justify-center gap-3 py-3.5 rounded-xl font-bold text-sm border transition-all hover:bg-white/5\" style={{ borderColor: 'rgba(255,255,255,0.15)', color: 'white' }}>\n              <svg width=\"18\" height=\"18\" viewBox=\"0 0 24 24\"><path fill=\"#4285F4\" d=\"M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z\"/><path fill=\"#34A853\" d=\"M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z\"/><path fill=\"#FBBC05\" d=\"M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l3.66-2.84z\"/><path fill=\"#EA4335\" d=\"M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z\"/></svg>\n              Continuar com Google\n            </button>\n            <div className=\"flex items-center gap-3\">\n              <div className=\"flex-1 h-px\" style={{ background: 'rgba(255,255,255,0.08)' }} />\n              <span className=\"text-xs\" style={{ color: 'rgba(255,255,255,0.3)' }}>ou</span>\n              <div className=\"flex-1 h-px\" style={{ background: 'rgba(255,255,255,0.08)' }} />\n            </div>\n            <button onClick={() => setMode('login')} className=\"w-full py-3.5 rounded-xl font-bold text-sm transition-all\" style={{ background: '#6C63FF', color: 'white' }}>\n              Entrar com email\n            </button>\n            <button onClick={() => setMode('register')} className=\"w-full py-3.5 rounded-xl font-bold text-sm border transition-all hover:bg-white/5\" style={{ borderColor: 'rgba(255,255,255,0.1)', color: 'rgba(255,255,255,0.6)' }}>\n              Criar conta com email\n            </button>\n            <button onClick={onClose} className=\"w-full py-2 text-xs\" style={{ color: 'rgba(255,255,255,0.25)' }}>\n              Continuar sem conta\n            </button>\n          </div>\n        )}\n\n        {(mode === 'login' || mode === 'register') && (\n          <div className=\"space-y-3\">\n            <input\n              className=\"w-full rounded-xl px-4 py-3 text-sm text-white outline-none border\"\n              style={{ background: 'rgba(255,255,255,0.05)', borderColor: error ? '#FF525244' : 'rgba(255,255,255,0.1)' }}\n              placeholder=\"Email\"\n              type=\"email\"\n              value={email}\n              onChange={e => { setEmail(e.target.value); setError(''); }}\n              inputMode=\"email\"\n              autoCapitalize=\"none\"\n            />\n            <input\n              className=\"w-full rounded-xl px-4 py-3 text-sm text-white outline-none border\"\n              style={{ background: 'rgba(255,255,255,0.05)', borderColor: error ? '#FF525244' : 'rgba(255,255,255,0.1)' }}\n              placeholder=\"Senha (m\u00ednimo 6 caracteres)\"\n              type=\"password\"\n              value={password}\n              onChange={e => { setPassword(e.target.value); setError(''); }}\n            />\n            {mode === 'register' && (\n              <div className=\"relative\">\n                <input\n                  className=\"w-full rounded-xl px-4 py-3 text-sm text-white outline-none border\"\n                  style={{ background: 'rgba(255,255,255,0.05)', borderColor: 'rgba(255,255,255,0.1)' }}\n                  placeholder=\"WhatsApp (opcional)\"\n                  type=\"tel\"\n                  value={phone}\n                  onChange={e => setPhone(e.target.value)}\n                  inputMode=\"tel\"\n                />\n                <span className=\"absolute right-3 top-1/2 -translate-y-1/2 text-xs\" style={{ color: 'rgba(255,255,255,0.25)' }}>opcional</span>\n              </div>\n            )}\n            {error && <p className=\"text-xs px-1\" style={{ color: '#FF5252' }}>{error}</p>}\n            {mode === 'register' && (\n              <div className=\"px-1 py-2 rounded-xl text-xs text-center\" style={{ background: 'rgba(247,183,49,0.08)', color: '#F7B731' }}>\n                \ud83e\ude99 +{WELCOME_BONUS} VotaCoins de boas-vindas ao cadastrar!\n              </div>\n            )}\n            <button\n              onClick={handleEmailAuth}\n              disabled={loading || !email || password.length < 6}\n              className=\"w-full py-3.5 rounded-xl font-black text-sm transition-all\"\n              style={{\n                background: email && password.length >= 6 ? '#6C63FF' : 'rgba(255,255,255,0.07)',\n                color: email && password.length >= 6 ? 'white' : 'rgba(255,255,255,0.3)',\n                fontFamily: 'var(--font-display)',\n                letterSpacing: '0.1em',\n              }}\n            >\n              {loading ? 'AGUARDE...' : mode === 'login' ? 'ENTRAR' : 'CADASTRAR'}\n            </button>\n            <button onClick={() => setMode(mode === 'login' ? 'register' : 'login')} className=\"w-full py-2 text-xs text-center\" style={{ color: 'rgba(255,255,255,0.35)' }}>\n              {mode === 'login' ? 'N\u00e3o tem conta? Cadastre-se' : 'J\u00e1 tem conta? Entre'}\n            </button>\n          </div>\n        )}\n      </div>\n    </div>\n  );\n}\n");
fs.writeFileSync('src/lib/polls.ts', "import {\n  collection, doc, getDocs, addDoc, updateDoc,\n  increment, onSnapshot, orderBy, query, where,\n  serverTimestamp, setDoc, getDoc,\n} from 'firebase/firestore';\nimport { signInAnonymously, GoogleAuthProvider, signInWithPopup } from 'firebase/auth';\nimport { db, auth } from './firebase';\n\nexport function generateSlug(question: string): string {\n  return question\n    .toLowerCase()\n    .normalize('NFD')\n    .replace(/[\u0300-\u036f]/g, '')\n    .replace(/[^a-z0-9\\s-]/g, '')\n    .trim()\n    .replace(/\\s+/g, '-')\n    .slice(0, 80)\n    + '-' + Math.random().toString(36).slice(2, 7);\n}\n\nexport async function getPollBySlug(slug: string) {\n  const q = query(collection(db, 'polls'), where('slug', '==', slug));\n  const snap = await getDocs(q);\n  if (snap.empty) return null;\n  return { id: snap.docs[0].id, ...snap.docs[0].data() };\n}\n\nexport async function ensureAuth() {\n  if (!auth.currentUser) {\n    await signInAnonymously(auth);\n  }\n  return auth.currentUser!;\n}\n\nexport async function signInWithGoogle() {\n  const provider = new GoogleAuthProvider();\n  return signInWithPopup(auth, provider);\n}\n\nexport function subscribeToPolls(callback: (polls: any[]) => void) {\n  const q = query(collection(db, 'polls'), orderBy('createdAt', 'desc'));\n  return onSnapshot(q, (snap) => {\n    const polls = snap.docs.map((d, i) => ({ id: d.id, ...d.data(), _order: (d.data() as any).order ?? i }));\n    polls.sort((a, b) => a._order - b._order);\n    callback(polls);\n  });\n}\n\nexport async function getUserVotes(userId: string) {\n  const snap = await getDocs(collection(db, `users/${userId}/votes`));\n  const votes: Record<string, string> = {};\n  snap.forEach(d => { votes[d.id] = d.data().choice; });\n  return votes;\n}\n\nexport async function castVote(pollId: string, choice: string, userId: string, city?: string, isAnonymous?: boolean) {\n  await setDoc(doc(db, `users/${userId}/votes/${pollId}`), {\n    choice, votedAt: serverTimestamp(), city: city || null,\n  });\n  const field = choice === 'A' ? 'votesA' : 'votesB';\n  const cityField = city ? `cities.${city}.${choice === 'A' ? 'votesA' : 'votesB'}` : null;\n  const update: any = { [field]: increment(1), totalVotes: increment(1) };\n  if (cityField) update[cityField] = increment(1);\n  await updateDoc(doc(db, 'polls', pollId), update);\n  // Increment voteCount and votaCoins only for non-anonymous users\n  if (!isAnonymous) {\n    setDoc(doc(db, 'members', userId), {\n      voteCount: increment(1),\n      votaCoins: increment(1),\n    }, { merge: true }).catch(() => null);\n  }\n}\n\nexport async function createPoll({ question, optionA, optionB, tag, color, userId }: any) {\n  const snap = await getDocs(collection(db, 'polls'));\n  const lastOrder = snap.size;\n  return addDoc(collection(db, 'polls'), {\n    question, optionA, optionB, tag, color,\n    votesA: 0, votesB: 0, totalVotes: 0,\n    cities: {},\n    slug: generateSlug(question),\n    order: lastOrder,\n    createdBy: userId,\n    createdAt: serverTimestamp(),\n  });\n}\n\nexport async function seedPolls() {\n  const existing = await getDocs(collection(db, 'polls'));\n  if (!existing.empty) return;\n  const polls = [\n    { question: 'Voc\u00ea preferiria:', optionA: { emoji: '\ud83c\udf55', label: 'Pizza todo dia', sublabel: 'sem exce\u00e7\u00e3o' }, optionB: { emoji: '\ud83c\udf54', label: 'Hamb\u00farguer todo dia', sublabel: 'sem exce\u00e7\u00e3o' }, tag: 'comida', color: '#FF6B35', votesA: 6312, votesB: 3841 },\n    { question: 'Voc\u00ea aceitaria:', optionA: { emoji: '\ud83d\udcb0', label: 'R$1 milh\u00e3o agora', sublabel: 'mas sem voltar no tempo' }, optionB: { emoji: '\ud83d\udd50', label: 'Voltar aos 18', sublabel: 'sem dinheiro' }, tag: 'vida', color: '#6C63FF', votesA: 4521, votesB: 7893 },\n    { question: 'Quem \u00e9 maior?', optionA: { emoji: '\ud83d\udc10', label: 'Messi', sublabel: 'Argentina' }, optionB: { emoji: '\ud83d\udd34', label: 'Cristiano Ronaldo', sublabel: 'Portugal' }, tag: 'esporte', color: '#00C9A7', votesA: 14230, votesB: 12891 },\n    { question: 'Onde voc\u00ea moraria?', optionA: { emoji: '\ud83c\udfdd\ufe0f', label: 'Na praia', sublabel: 'calor e areia' }, optionB: { emoji: '\ud83c\udfd4\ufe0f', label: 'Na montanha', sublabel: 'frio e natureza' }, tag: 'estilo de vida', color: '#FF4E8C', votesA: 8943, votesB: 5612 },\n    { question: 'Voc\u00ea prefere:', optionA: { emoji: '\ud83c\udf19', label: 'Ser coruja', sublabel: 'dormir tarde' }, optionB: { emoji: '\u2600\ufe0f', label: 'Ser madrugador', sublabel: 'acordar cedo' }, tag: 'rotina', color: '#F7B731', votesA: 9871, votesB: 4320 },\n    { question: 'Se pudesse escolher:', optionA: { emoji: '\ud83e\uddb8', label: 'Voar', sublabel: 'sem limites' }, optionB: { emoji: '\ud83e\udde0', label: 'Ler mentes', sublabel: 'de qualquer pessoa' }, tag: 'superpoderes', color: '#FF5252', votesA: 11203, votesB: 9874 },\n  ];\n  for (const p of polls) {\n    await addDoc(collection(db, 'polls'), {\n      ...p, totalVotes: p.votesA + p.votesB, cities: {},\n      createdBy: 'system', createdAt: serverTimestamp(),\n    });\n  }\n}\n");
fs.writeFileSync('src/components/PollCard.tsx', "'use client';\nimport { useState } from 'react';\nimport { doc, setDoc, serverTimestamp } from 'firebase/firestore';\nimport { db } from '@/lib/firebase';\n\nfunction fmt(n: number) {\n  if (n >= 1000000) return (n / 1000000).toFixed(1) + 'M';\n  if (n >= 1000) return (n / 1000).toFixed(1) + 'k';\n  return String(n);\n}\n\nexport default function PollCard({ poll, onVote, userVote, userId, isFirstVote, onSubscribed, isAnon, onShowAuth }: {\n  poll: any;\n  onVote: (id: string, choice: string) => void;\n  userVote?: string;\n  userId?: string;\n  isFirstVote?: boolean;\n  onSubscribed?: () => void;\n  isAnon?: boolean;\n  onShowAuth?: () => void;\n}) {\n  const [hovering, setHovering] = useState<string | null>(null);\n  const [phone, setPhone] = useState('');\n  const [phoneSaved, setPhoneSaved] = useState(false);\n  const [savingPhone, setSavingPhone] = useState(false);\n\n  const voted = !!userVote;\n  const total = (poll.votesA || 0) + (poll.votesB || 0);\n  const pctA = total > 0 ? Math.round((poll.votesA / total) * 100) : 50;\n  const pctB = 100 - pctA;\n\n  const formatPhone = (v: string) => {\n    const digits = v.replace(/\\D/g, '').slice(0, 11);\n    if (digits.length <= 2) return digits;\n    if (digits.length <= 7) return `(${digits.slice(0,2)}) ${digits.slice(2)}`;\n    return `(${digits.slice(0,2)}) ${digits.slice(2,7)}-${digits.slice(7)}`;\n  };\n\n  const handleSavePhone = async () => {\n    const digits = phone.replace(/\\D/g, '');\n    if (digits.length < 10 || !userId) return;\n    setSavingPhone(true);\n    await setDoc(doc(db, 'subscribers', userId), {\n      phone: digits,\n      userId,\n      subscribedAt: serverTimestamp(),\n      active: true,\n    });\n    setPhoneSaved(true);\n    setSavingPhone(false);\n    if (onSubscribed) onSubscribed();\n  };\n\n  const options = [\n    { key: 'A', data: poll.optionA, pct: pctA, votes: poll.votesA || 0 },\n    { key: 'B', data: poll.optionB, pct: pctB, votes: poll.votesB || 0 },\n  ];\n\n  return (\n    <div\n      className=\"relative rounded-2xl p-6 mb-4 border transition-all duration-300\"\n      style={{\n        background: 'rgba(255,255,255,0.03)',\n        borderColor: voted ? poll.color + '33' : 'rgba(255,255,255,0.07)',\n      }}\n    >\n      {/* Pol\u00eamica do Dia banner */}\n      {poll.hotOfDay && (\n        <div\n          className=\"flex items-center gap-2 px-4 py-2 rounded-xl mb-3 text-xs font-black tracking-widest\"\n          style={{\n            background: 'linear-gradient(90deg, #FF4E8C22, #FF6B3522)',\n            border: '1px solid #FF4E8C44',\n          }}\n        >\n          <span className=\"text-base animate-pulse\">\ud83d\udd25</span>\n          <span style={{ background: 'linear-gradient(90deg, #FF4E8C, #FF6B35)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>\n            POL\u00caMICA DO DIA\n          </span>\n        </div>\n      )}\n\n      {/* Tag */}\n      <div className=\"flex items-center gap-2 mb-4\">\n        <div\n          className=\"flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-bold tracking-widest uppercase border\"\n          style={{ color: poll.color, borderColor: poll.color + '44', background: poll.color + '11' }}\n        >\n          <span className=\"w-1.5 h-1.5 rounded-full\" style={{ background: poll.color }} />\n          {poll.tag}\n        </div>\n        {voted && (\n          <span className=\"ml-auto text-xs\" style={{ color: 'rgba(255,255,255,0.3)' }}>\n            {fmt(total)} votos\n          </span>\n        )}\n      </div>\n\n      {/* Question */}\n      <p className=\"text-sm mb-5\" style={{ color: 'rgba(255,255,255,0.4)', fontFamily: 'var(--font-body)' }}>\n        {poll.question}\n      </p>\n\n      {/* Options */}\n      <div className=\"space-y-3\">\n        {options.map(({ key, data, pct, votes }) => {\n          const isWinner = voted && pct > 50;\n          const isUserVote = userVote === key;\n          const isLoser = voted && !isUserVote;\n\n          return (\n            <button\n              key={key}\n              onClick={() => !voted && onVote(poll.id, key)}\n              onMouseEnter={() => !voted && setHovering(key)}\n              onMouseLeave={() => setHovering(null)}\n              disabled={voted}\n              className=\"relative w-full flex items-center gap-4 p-4 rounded-xl border-2 overflow-hidden transition-all duration-300 text-left\"\n              style={{\n                borderColor: isUserVote ? poll.color : hovering === key ? poll.color + '66' : 'rgba(255,255,255,0.08)',\n                background: isUserVote ? poll.color + '15' : hovering === key ? poll.color + '08' : 'rgba(255,255,255,0.03)',\n                opacity: isLoser ? 0.4 : 1,\n                cursor: voted ? 'default' : 'pointer',\n              }}\n            >\n              {voted && (\n                <div\n                  className=\"absolute inset-y-0 left-0 transition-all duration-700\"\n                  style={{\n                    width: `${pct}%`,\n                    background: isUserVote ? poll.color + '20' : 'rgba(255,255,255,0.03)',\n                  }}\n                />\n              )}\n              <span className=\"relative text-3xl\">{data.emoji}</span>\n              <div className=\"relative flex-1 min-w-0\">\n                <div className=\"font-bold text-white text-sm truncate\">{data.label}</div>\n                {data.sublabel && (\n                  <div className=\"text-xs mt-0.5\" style={{ color: 'rgba(255,255,255,0.35)' }}>{data.sublabel}</div>\n                )}\n              </div>\n              {voted ? (\n                <div className=\"relative text-right shrink-0\">\n                  <div className=\"text-xl font-black\" style={{ color: isUserVote ? poll.color : 'rgba(255,255,255,0.35)', fontFamily: 'var(--font-display)', letterSpacing: '0.05em' }}>\n                    {pct}%\n                  </div>\n                  <div className=\"text-xs\" style={{ color: 'rgba(255,255,255,0.25)' }}>{fmt(votes)}</div>\n                </div>\n              ) : (\n                <div\n                  className=\"relative w-7 h-7 rounded-full border-2 flex items-center justify-center text-xs font-bold shrink-0\"\n                  style={{ borderColor: 'rgba(255,255,255,0.15)', color: 'rgba(255,255,255,0.3)' }}\n                >\n                  {key}\n                </div>\n              )}\n            </button>\n          );\n        })}\n      </div>\n\n      {/* Footer ap\u00f3s votar */}\n      {voted && (\n        <div className=\"mt-4 pt-4 border-t\" style={{ borderColor: 'rgba(255,255,255,0.06)' }}>\n\n          {/* WhatsApp capture \u2014 s\u00f3 no primeiro voto, s\u00f3 para membros */}\n          {isFirstVote && isAnon && onShowAuth && (\n            <div className=\"mt-3 p-3 rounded-xl text-center cursor-pointer\" onClick={onShowAuth} style={{ background: 'rgba(247,183,49,0.08)', border: '1px solid rgba(247,183,49,0.2)' }}>\n              <p className=\"text-xs font-black\" style={{ color: '#F7B731' }}>\ud83e\ude99 Cadastre-se e ganhe VotaCoins!</p>\n              <p className=\"text-xs mt-0.5\" style={{ color: 'rgba(255,255,255,0.4)' }}>1 voto = 1 VotaCoin = R$0,01 \u00b7 Saque a partir de R$20</p>\n            </div>\n          )}\n          {isFirstVote && isAnon && onShowAuth && (\n            <div className=\"mt-3 p-3 rounded-xl text-center cursor-pointer\" onClick={onShowAuth} style={{ background: 'rgba(247,183,49,0.08)', border: '1px solid rgba(247,183,49,0.2)' }}>\n              <p className=\"text-xs font-black\" style={{ color: '#F7B731' }}>\ud83e\ude99 Cadastre-se e ganhe VotaCoins!</p>\n              <p className=\"text-xs mt-0.5\" style={{ color: 'rgba(255,255,255,0.4)' }}>1 voto = 1 VotaCoin = R$0,01 \u00b7 Saque a partir de R$20</p>\n            </div>\n          )}\n          {isFirstVote && !phoneSaved && !isAnon && (\n            <div className=\"mb-3 p-3 rounded-xl\" style={{ background: 'rgba(37,211,102,0.07)', border: '1px solid #25D36622' }}>\n              <p className=\"text-xs font-black mb-2\" style={{ color: '#25D366' }}>\ud83d\udd25 Receba a Pol\u00eamica do Dia no WhatsApp</p>\n              <div className=\"flex gap-2\">\n                <div className=\"relative flex-1\">\n                  <span className=\"absolute left-3 top-1/2 -translate-y-1/2 text-xs font-bold\" style={{ color: 'rgba(255,255,255,0.3)' }}>+55</span>\n                  <input\n                    className=\"w-full rounded-lg pl-9 pr-3 py-2 text-xs text-white outline-none border\"\n                    style={{ background: 'rgba(255,255,255,0.05)', borderColor: 'rgba(255,255,255,0.1)' }}\n                    placeholder=\"(11) 99999-9999\"\n                    value={phone}\n                    onChange={e => setPhone(formatPhone(e.target.value))}\n                    inputMode=\"numeric\"\n                  />\n                </div>\n                <button\n                  onClick={handleSavePhone}\n                  disabled={phone.replace(/\\D/g,'').length < 10 || savingPhone}\n                  className=\"px-3 py-2 rounded-lg text-xs font-black shrink-0\"\n                  style={{\n                    background: phone.replace(/\\D/g,'').length >= 10 ? '#25D366' : 'rgba(255,255,255,0.07)',\n                    color: phone.replace(/\\D/g,'').length >= 10 ? 'white' : 'rgba(255,255,255,0.3)',\n                  }}\n                >\n                  {savingPhone ? '...' : 'Quero!'}\n                </button>\n              </div>\n            </div>\n          )}\n\n          {phoneSaved && (\n            <div className=\"mb-3 p-3 rounded-xl text-center\" style={{ background: 'rgba(37,211,102,0.07)', border: '1px solid #25D36622' }}>\n              <p className=\"text-xs font-black\" style={{ color: '#25D366' }}>\u2705 Cadastrado! Voc\u00ea vai receber a Pol\u00eamica do Dia \ud83d\udd25</p>\n            </div>\n          )}\n\n          <div className=\"flex items-center justify-between\">\n            <span className=\"text-xs\" style={{ color: 'rgba(255,255,255,0.25)' }}>\n              {userVote === 'A' ? poll.optionA.emoji : poll.optionB.emoji} Voc\u00ea votou em {userVote === 'A' ? poll.optionA.label : poll.optionB.label}\n            </span>\n            <button\n              onClick={() => {\n                const url = poll.slug ? `https://votaai.app/p/${poll.slug}` : 'https://votaai.app';\n                const text = `\ud83d\udd25 ${poll.question}\\n${poll.optionA.emoji} ${poll.optionA.label} (${pctA}%) vs ${poll.optionB.emoji} ${poll.optionB.label} (${pctB}%)\\n\\nVote tamb\u00e9m! \ud83d\udc49 ${url}`;\n                if (navigator.share) navigator.share({ title: poll.question, text });\n                else navigator.clipboard.writeText(text);\n              }}\n              className=\"text-xs px-3 py-1.5 rounded-lg border transition-colors\"\n              style={{ borderColor: 'rgba(255,255,255,0.1)', color: 'rgba(255,255,255,0.4)' }}\n            >\n              \ud83d\udce4 Compartilhar\n            </button>\n          </div>\n        </div>\n      )}\n    </div>\n  );\n}\n");
